{"procName":"dbo.sp_tinhluyke_optimized","body":"CREATE   PROCEDURE dbo.sp_TinhLuyKe_Optimized
    @Nam INT,
    @Thang INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @NgayDauThang DATE = DATEFROMPARTS(@Nam, @Thang, 1);
    DECLARE @NgayCuoiThang DATE = EOMONTH(@NgayDauThang);

    PRINT CONCAT('=== BẮT ĐẦU TÍNH LŨY KẾ THÁNG ', @Thang, '/', @Nam, ' ===');

    IF OBJECT_ID('tempdb..#LuyKe') IS NOT NULL DROP TABLE #LuyKe;

    /* 1️⃣ LẤY DANH SÁCH VẬT TƯ + TỒN ĐẦU (soluong + nhapton) */
    SELECT 
        m.mavt,
        ISNULL(t.soluong, 0) + ISNULL(t.nhapton, 0) AS sltondau,
        0 AS slnhap,
        0 AS slxuat,
        0 AS sltoncuoi,
        0 AS dgton,
        NULL AS taikhoan
    INTO #LuyKe
    FROM tr_material m
    LEFT JOIN tr_tonkho_sum t ON t.mavt = m.mavt
    WHERE ISNULL(m.xoa, 'N') = 'N';

    /* 2️⃣ NHẬP HỢP LỆ */
    UPDATE l
    SET l.slnhap = ISNULL(n.slnhap, 0),
        l.taikhoan = n.taikhoan
    FROM #LuyKe l
    LEFT JOIN (
        SELECT n.mavt, SUM(n.slnhap) AS slnhap, MAX(n.taikhoan) AS taikhoan
        FROM tr_ctphieunhap n
        INNER JOIN tr_phieunhap pn ON pn.sopn = n.sopn
        WHERE pn.active = 1 
          AND ISNULL(n.gianhap, 0) > 0
          AND n.ngaynhap BETWEEN @NgayDauThang AND @NgayCuoiThang
        GROUP BY n.mavt
    ) n ON n.mavt = l.mavt;

    /* 3️⃣ XUẤT HỢP LỆ */
    UPDATE l
    SET l.slxuat = ISNULL(x.slxuat, 0),
        l.taikhoan = COALESCE(l.taikhoan, x.taikhoan)
    FROM #LuyKe l
    LEFT JOIN (
        SELECT x.mact AS mavt, SUM(x.soluong) AS slxuat, MAX(x.taikhoan) AS taikhoan
        FROM tr_ctphieuxuat x
        INNER JOIN tr_phieuxuat px ON px.sopx = x.phieuxuat
        WHERE px.active = 1 
          AND ISNULL(x.giaxuat, 0) > 0
          AND x.ngaytao BETWEEN @NgayDauThang AND @NgayCuoiThang
        GROUP BY x.mact
    ) x ON x.mavt = l.mavt;

    /* 4️⃣ LẤY TÀI KHOẢN GẦN NHẤT (THÁNG TRƯỚC) CHO MÃ KHÔNG PHÁT SINH */
    UPDATE l
    SET l.taikhoan = COALESCE(l.taikhoan, lk.taikhoan)
    FROM #LuyKe l
    OUTER APPLY (
        SELECT TOP 1 taikhoan
        FROM tr_material_luyke lk
        WHERE lk.mavt = l.mavt
          AND lk.taikhoan IS NOT NULL
        ORDER BY lk.ngay DESC
    ) lk;

    /* 5️⃣ TÍNH TỒN CUỐI */
    UPDATE l
    SET l.sltoncuoi = ISNULL(l.sltondau,0) + ISNULL(l.slnhap,0) - ISNULL(l.slxuat,0),
        l.dgton = CASE WHEN (ISNULL(l.sltondau,0) + ISNULL(l.slnhap,0)) > 0 THEN 1 ELSE 0 END
    FROM #LuyKe l;

    /* 6️⃣ KHỚP VỚI TỒN KHO THỰC TẾ */
    UPDATE l
    SET l.sltoncuoi = CASE 
                          WHEN ISNULL(t.soluong,0) + ISNULL(t.nhapton,0) < 0 THEN 0
                          ELSE ISNULL(t.soluong,0) + ISNULL(t.nhapton,0)
                      END
    FROM #LuyKe l
    INNER JOIN tr_tonkho_sum t ON t.mavt = l.mavt;

    /* 7️⃣ XÓA DỮ LIỆU CŨ */
    DELETE FROM tr_material_luyke 
    WHERE loai = 'LuyKeThang'
      AND ngay = @NgayDauThang;

    /* 8️⃣ CHÈN LŨY KẾ MỚI */
    INSERT INTO tr_material_luyke (
        Id, loai, mavt, ngay, sltondau, slnhap, slxuat, sltoncuoi, dgton, taikhoan
    )
    SELECT 
        NEWID(),
        'LuyKeThang',
        mavt,
        @NgayDauThang,
        ISNULL(sltondau,0),
        ISNULL(slnhap,0),
        ISNULL(slxuat,0),
        CASE WHEN ISNULL(sltoncuoi,0) < 0 THEN 0 ELSE ISNULL(sltoncuoi,0) END,
        ISNULL(dgton,0),
        taikhoan  -- kiểu INT
    FROM #LuyKe;

    PRINT CONCAT('=== HOÀN TẤT LŨY KẾ THÁNG ', @Thang, '/', @Nam, ' ===');
END;","parseAnalysis":{"readsTables":["dbo.tr_ctphieunhap","dbo.tr_ctphieuxuat","dbo.tr_material","dbo.tr_material_luyke","dbo.tr_phieunhap","dbo.tr_phieuxuat","dbo.tr_tonkho_sum"],"writesTables":["dbo.l","dbo.tr_material_luyke"],"flags":["has-group-by","has-temp-table","writes-multi-table"],"suggestedTier":"D"},"tablesEnriched":{"dbo.dqt_pallet_chitiet":"dqt_pallet_chitiet","dbo.dqt_thongke_phoi":"dqt_thongke_phoi","dbo.mes_hoso_donhang":"mes_hoso_donhang","dbo.ps_kehoach_donhang":"ps_kehoach_donhang","dbo.ps_kehoach_donhang_trangthai":"ps_kehoach_donhang_trangthai","dbo.tr_bophan":"tr_bophan","dbo.tr_chitiet_hangtrang":"tr_chitiet_hangtrang","dbo.tr_common":"tr_common","dbo.tr_dinhmuc_donggoi":"tr_dinhmuc_donggoi","dbo.tr_dinhmuc_govan":"tr_dinhmuc_govan","dbo.tr_dinhmuc_hangtrang":"tr_dinhmuc_hangtrang","dbo.tr_dinhmuc_ngukim":"tr_dinhmuc_ngukim","dbo.tr_dinhmuc_son":"tr_dinhmuc_son","dbo.tr_dinhmuc_son_new":"tr_dinhmuc_son_new","dbo.tr_dinhmuc_son_theomau":"tr_dinhmuc_son_theomau","dbo.tr_dondathang":"tr_dondathang","dbo.tr_dondathang_chitiet":"tr_dondathang_chitiet","dbo.tr_gridview_column":"tr_gridview_column","dbo.tr_luutrinh_sanxuat":"tr_luutrinh_sanxuat","dbo.tr_material":"tr_material","dbo.tr_nguyenlieu_gva":"tr_nguyenlieu_gva","dbo.tr_order":"tr_order","dbo.tr_order_detail":"tr_order_detail","dbo.tr_sanpham":"tr_sanpham","dbo.tr_tinhtrang_fsc":"tr_tinhtrang_fsc"}}
